 295 | 
 296 |                     } catch (e) { console.error("[ERROR] Hydration Failed for anchor:", e); }
 297 |                 });
 298 | 
 299 |                 // 5. Setup Sentence Pass-through logic (needs access to 'doc')
 300 |                 const win = iframe.contentWindow;
 301 |                 win.highlightAt = (clientX, clientY) => {
 302 |                     const hitElement = doc.elementFromPoint(clientX, clientY);
 303 |                     const interactive = hitElement?.closest('.q-opt-btn, .q-submit');
 304 |                     if (interactive) {
 305 |                         interactive.click();
 306 |                         return { found: true, isAction: true };
 307 |                     }
 308 | 
 309 |                     if (!win.CSS?.highlights) return false;
 310 | 
 311 |                     let range;
 312 |                     if (doc.caretRangeFromPoint) {
 313 |                         range = doc.caretRangeFromPoint(clientX, clientY);
 314 |                     } else if (doc.caretPositionFromPoint) {
 315 |                         const pos = doc.caretPositionFromPoint(clientX, clientY);
 316 |                         range = doc.createRange();
 317 |                         range.setStart(pos.offsetNode, pos.offset);
 318 |                         range.collapse(true);
 319 |                     }
 320 | 
 321 |                     const targetNode = range?.startContainer;
 322 |                     const targetElement = targetNode?.nodeType === 3 ? targetNode.parentElement : targetNode;
 323 |                     if (targetElement?.closest('.miron-portal-container')) {
 324 |                         win.CSS.highlights.clear();
 325 |                         return { found: true, isAction: true };
 326 |                     }
 327 | 
 328 |                     if (!range || !docBody.contains(targetNode) || targetNode.nodeType !== 3) {
 329 |                         win.CSS.highlights.clear();
 330 |                         return false;
 331 |                     }
 332 | 
 333 |                     const pageBoundary = targetElement.closest('.page, .page-container, .text-container') || docBody;
 334 |                     const sentenceRange = findSentenceRange(doc, targetNode, range.startOffset, pageBoundary);
 335 |                     
 336 |                     if (sentenceRange) {
 337 |                         const highlight = new win.Highlight(sentenceRange);
 338 |                         win.CSS.highlights.set("sentence-focus", highlight);
 339 |                         const rect = sentenceRange.getBoundingClientRect();
 340 |                         return {
 341 |                             found: true,
 342 |                             text: sentenceRange.toString(),
 343 |                             rect: { x: rect.x, y: rect.y, width: rect.width, height: rect.height }
 344 |                         };
 345 |                     }
 346 |                     win.CSS.highlights.clear();
 347 |                     return { found: false };
 348 |                 };
 349 | 
 350 |                 // Helper inside the closure
 351 |                 function findSentenceRange(rootDoc, startNode, startOffset, pageBoundary) {
 352 |                     const sentenceEndRegex = /[.!?]/;
 353 |                     const walker = rootDoc.createTreeWalker(pageBoundary, NodeFilter.SHOW_TEXT, null, false);
 354 | 
 355 |                     let finalStartNode = startNode, finalStartOffset = 0;
 356 |                     let textBefore = startNode.textContent.substring(0, startOffset);
 357 |                     let lastPuncIndex = -1;
 358 |                     for(let i = textBefore.length - 1; i >= 0; i--) if(sentenceEndRegex.test(textBefore[i])) { lastPuncIndex = i; break; }
 359 | 
 360 |                     if (lastPuncIndex !== -1) {
 361 |                         finalStartOffset = lastPuncIndex + 1;
 362 |                         if(startNode.textContent[finalStartOffset] === ' ') finalStartOffset++;
 363 |                     } else {
 364 |                         walker.currentNode = startNode;
 365 |                         let prevNode = walker.previousNode();
 366 |                         while (prevNode) {
 367 |                             const text = prevNode.textContent;
 368 |                             const idx = text.split('').reverse().join('').search(sentenceEndRegex);
 369 |                             if (idx !== -1) {
 370 |                                 finalStartNode = prevNode; finalStartOffset = text.length - idx;
 371 |                                 if(text[finalStartOffset] === ' ') finalStartOffset++;
 372 |                                 break;
 373 |                             }
 374 |                             finalStartNode = prevNode; finalStartOffset = 0;
 375 |                             prevNode = walker.previousNode();
 376 |                         }
 377 |                     }
 378 | 
 379 |                     let finalEndNode = startNode, finalEndOffset = startNode.textContent.length;
 380 |                     let textAfter = startNode.textContent.substring(startOffset);
 381 |                     let nextPuncIndex = textAfter.search(sentenceEndRegex);
 382 | 
 383 |                     if (nextPuncIndex !== -1) {
 384 |                         finalEndOffset = startOffset + nextPuncIndex + 1;
 385 |                     } else {
 386 |                         walker.currentNode = startNode;
 387 |                         let nextNode = walker.nextNode();
 388 |                         while (nextNode) {
 389 |                             const text = nextNode.textContent;
 390 |                             const puncIdx = text.search(sentenceEndRegex);
 391 |                             if (puncIdx !== -1) {
 392 |                                 finalEndNode = nextNode; finalEndOffset = puncIdx + 1;
 393 |                                 break;
 394 |                             }
 395 |                             finalEndNode = nextNode; finalEndOffset = text.length;
 396 |                             nextNode = walker.nextNode();
 397 |                         }
 398 |                     }
 399 | 
 400 |                     const r = rootDoc.createRange();
 401 |                     try { r.setStart(finalStartNode, finalStartOffset); r.setEnd(finalEndNode, finalEndOffset); return r; }
 402 |                     catch (e) { return null; }
 403 |                 }
 404 | 
 405 |                 // 6. FINAL MEASUREMENT & UI REFRESH
 406 |                 requestAnimationFrame(() => {
 407 |                     const finalW = Math.max(docBody.scrollWidth, docEl.scrollWidth, 800);
 408 |                     const finalH = Math.max(docBody.scrollHeight, docEl.scrollHeight);
 409 |                     console.log(`%c[MEASUREMENT] Final: ${finalW}x${finalH}`, "color: #42d7b8; font-weight: bold;");
 410 | 
 411 |                     contentDims.current = { width: finalW, height: finalH };
 412 |                     if (layerRef.current) {
 413 |                         layerRef.current.style.width = `${finalW}px`;
 414 |                         layerRef.current.style.height = `${finalH}px`;
 415 |                     }
 416 | 
 417 |                     const vw = window.innerWidth;
 418 |                     minScaleLimit.current = vw / finalW;
 419 |                     state.current.scale = minScaleLimit.current;
 420 |                     console.groupEnd();
 421 |                 });
 422 | 
 423 |             } catch (err) {
 424 |                 console.error("[ERROR] handleIframeLoad failed:", err);
 425 |                 console.groupEnd();
 426 |             }
 427 |         }, 300);
 428 |     };
 429 | 
 430 |     // Apply Theme Changes
 431 |     useEffect(() => {
 432 |         if (iframeRef.current) {
 433 |             const doc = iframeRef.current.contentDocument || iframeRef.current.contentWindow.document;
 434 |             if (doc && doc.body) {
 435 |                 doc.body.className = `theme-${currentTheme}`;
 436 |             }
 437 |         }
 438 |     }, [currentTheme]);
 439 | 
 440 |     const toggleTheme = () => {
 441 |         const themes = ['light', 'sepia', 'dark'];
 442 |         const nextIndex = (themes.indexOf(currentTheme) + 1) % themes.length;
 443 |         setCurrentTheme(themes[nextIndex]);
 444 |         setIsFabActive(false);
 445 |     };
 446 | 
 447 |     const handleFitPage = () => {
 448 |         // Reset Zoom to Width Fit
 449 |         const currentRealY = state.current.y / state.current.scale;
 450 |         state.current.scale = minScaleLimit.current;
 451 |         state.current.x = 0;
 452 |         state.current.y = currentRealY * state.current.scale; // Maintain relative Y position
 453 |         velocity.current = { x: 0, y: 0 };
 454 |         setIsFabActive(false);
 455 |     };
 456 | 
 457 |     // --- OPTIMIZED PHYSICS ENGINE ---
 458 | 
 459 |     const applyConstraints = () => {
 460 |         const vw = window.innerWidth;
 461 |         const vh = window.innerHeight;
 462 |         const { width, height } = contentDims.current;
 463 |         const s = state.current;
 464 |         const v = velocity.current;
 465 |         
 466 |         const visualW = width * s.scale;
 467 |         const visualH = height * s.scale;
 468 | 
 469 |         // X Constraint
 470 |         if (visualW < vw) {
 471 |             s.x = (vw - visualW) / 2;
 472 |             v.x = 0;
 473 |         } else {
 474 |             if (s.x > 0) { s.x = 0; v.x = 0; }
 475 |             if (s.x < vw - visualW) { s.x = vw - visualW; v.x = 0; }
 476 |         }
 477 | 
 478 |         // Y Constraint
 479 |         if (visualH < vh) {
 480 |             s.y = (vh - visualH) / 2;
 481 |             v.y = 0;
 482 |         } else {
 483 |             if (s.y > 0) { s.y = 0; v.y = 0; }
 484 |             if (s.y < vh - visualH) { s.y = vh - visualH; v.y = 0; }
 485 |         }
 486 |     };
 487 | 
 488 |     // The Single Render Loop
 489 |     // Decouples input frequency from screen refresh rate for buttery smooth motion
 490 |     const loop = () => {
 491 |         // 1. Apply Physics if not dragging
 492 |         if (!input.current.isDragging) {
 493 |             const v = velocity.current;
 494 |             // Apply snap-stop: if velocity is low, kill it immediately
 495 |             if (Math.abs(v.x) < 0.5) v.x = 0;
 496 |             if (Math.abs(v.y) < 0.5) v.y = 0;
 497 | 
 498 |             if (v.x !== 0 || v.y !== 0) {
 499 |                 v.x *= CONFIG.friction;
 500 |                 v.y *= CONFIG.friction;
 501 |                 state.current.x += v.x;
 502 |                 state.current.y += v.y;
 503 |             }
 504 |         }
 505 | 
 506 |         // 2. Apply Constraints (Borders)
 507 |         applyConstraints();
 508 | 
 509 |         // 3. Render to DOM
 510 |         if (layerRef.current) {
 511 |             const { x, y, scale } = state.current;
 512 |             // Using transform3d for hardware acceleration
 513 |             layerRef.current.style.transform = `translate3d(${x}px, ${y}px, 0) scale(${scale})`;
 514 |         }
 515 | 
 516 |         // 4. Update UI (Slider & Pages)
 517 |         if (sliderRef.current && pageCountRef.current && contentDims.current.height > 0) {
 518 |             // Use Unscaled values for stability across Zoom levels
 519 |             const unscaledTotalH = contentDims.current.height;
 520 |             const unscaledY = Math.abs(state.current.y) / state.current.scale;
 521 |             const viewHeight = window.innerHeight / state.current.scale;
 522 |             
 523 |             // Slider Progress (0-100%)
 524 |             // We compare unscaled position against the maximum possible unscaled scroll
 525 |             const maxScroll = Math.max(1, unscaledTotalH - viewHeight);
 526 |             
 527 |             if (!input.current.isSliderDragging) {
 528 |                 const progress = (unscaledY / maxScroll) * 100;
 529 |                 sliderRef.current.value = Math.max(0, Math.min(100, progress));
 530 |             }
 531 | 
 532 |             // Page Count Logic (Standard Book Ratio 1.3)
