 352 |                 // Helper inside the closure
 353 |                 function findSentenceRange(rootDoc, startNode, startOffset, pageBoundary) {
 354 |                     const sentenceEndRegex = /[.!?]/;
 355 |                     const walker = rootDoc.createTreeWalker(pageBoundary, NodeFilter.SHOW_TEXT, null, false);
 356 | 
 357 |                     let finalStartNode = startNode, finalStartOffset = 0;
 358 |                     let textBefore = startNode.textContent.substring(0, startOffset);
 359 |                     let lastPuncIndex = -1;
 360 |                     for(let i = textBefore.length - 1; i >= 0; i--) if(sentenceEndRegex.test(textBefore[i])) { lastPuncIndex = i; break; }
 361 | 
 362 |                     if (lastPuncIndex !== -1) {
 363 |                         finalStartOffset = lastPuncIndex + 1;
 364 |                         if(startNode.textContent[finalStartOffset] === ' ') finalStartOffset++;
 365 |                     } else {
 366 |                         walker.currentNode = startNode;
 367 |                         let prevNode = walker.previousNode();
 368 |                         while (prevNode) {
 369 |                             const text = prevNode.textContent;
 370 |                             const idx = text.split('').reverse().join('').search(sentenceEndRegex);
 371 |                             if (idx !== -1) {
 372 |                                 finalStartNode = prevNode; finalStartOffset = text.length - idx;
 373 |                                 if(text[finalStartOffset] === ' ') finalStartOffset++;
 374 |                                 break;
 375 |                             }
 376 |                             finalStartNode = prevNode; finalStartOffset = 0;
 377 |                             prevNode = walker.previousNode();
 378 |                         }
 379 |                     }
 380 | 
 381 |                     let finalEndNode = startNode, finalEndOffset = startNode.textContent.length;
 382 |                     let textAfter = startNode.textContent.substring(startOffset);
 383 |                     let nextPuncIndex = textAfter.search(sentenceEndRegex);
 384 | 
 385 |                     if (nextPuncIndex !== -1) {
 386 |                         finalEndOffset = startOffset + nextPuncIndex + 1;
 387 |                     } else {
 388 |                         walker.currentNode = startNode;
 389 |                         let nextNode = walker.nextNode();
 390 |                         while (nextNode) {
 391 |                             const text = nextNode.textContent;
 392 |                             const puncIdx = text.search(sentenceEndRegex);
 393 |                             if (puncIdx !== -1) {
 394 |                                 finalEndNode = nextNode; finalEndOffset = puncIdx + 1;
 395 |                                 break;
 396 |                             }
 397 |                             finalEndNode = nextNode; finalEndOffset = text.length;
 398 |                             nextNode = walker.nextNode();
 399 |                         }
 400 |                     }
 401 | 
 402 |                     const r = rootDoc.createRange();
 403 |                     try { r.setStart(finalStartNode, finalStartOffset); r.setEnd(finalEndNode, finalEndOffset); return r; }
 404 |                     catch (e) { return null; }
